ALGORITHM Convert_SOP_to_NAND_NAND
INPUT: Boolean expression in SOP form: F = A·B + C·D + ...
OUTPUT: NAND-NAND implementation structure

BEGIN
 // Step 1: Apply double complement to the entire expression
 // F = (expression)''

 // Step 2: Apply De Morgan's theorem to inner complement
 // F = ((A·B)' · (C·D)' · ...)'
 // This creates a NAND of NANDs

 // Step 3: Convert each AND operation to NAND
 // Replace each AND gate with a NAND gate
 // (A·B) becomes NAND(A,B)
 // (C·D) becomes NAND(C,D)

 // Step 4: Replace the outer OR with NAND
 // The final NAND gate inverts the product of all NAND outputs

 // Step 5: Handle single-variable terms
 // If a term is a single literal (not a product),
 // add an inverter (use NAND with both inputs = that literal)
 // Single literal C becomes NAND(C,C) = C'

 PRINT "NAND-NAND Implementation:"
 PRINT " Level 1: NAND gates for each product term"
 PRINT " Level 2: NAND gate for sum of products"
 PRINT " Add NAND gates as inverters for single literals"
END

ALGORITHM Implement_NOT_using_NAND
INPUT: Input A
OUTPUT: NOT A using NAND gate
BEGIN
 // Connect both inputs of NAND to the same signal
 OUTPUT = NAND(A, A)
 // F = (A · A)' = A' (by idempotent and complement laws)
 RETURN OUTPUT
END

ALGORITHM Implement_AND_using_NAND
INPUT: Inputs A, B
OUTPUT: A·B using NAND gates
BEGIN
 // Step 1: NAND A and B
 TEMP = NAND(A, B) // TEMP = (A·B)'
 // Step 2: NAND the result with itself to invert
 OUTPUT = NAND(TEMP, TEMP)
 // OUTPUT = ((A·B)')' = A·B
 RETURN OUTPUT
END

ALGORITHM Implement_OR_using_NAND
INPUT: Inputs A, B
OUTPUT: A+B using NAND gates
BEGIN
 // Step 1: Invert both inputs using NAND as NOT
 A_NOT = NAND(A, A) // A'
 B_NOT = NAND(B, B) // B'
 // Step 2: NAND the inverted inputs
 OUTPUT = NAND(A_NOT, B_NOT)
 // OUTPUT = (A' · B')' = A + B (De Morgan's theorem)
 RETURN OUTPUT
END

/*
 * NAND and NOR Universal Gate Implementation
 * Demonstrates: NAND-NAND and NOR-NOR implementations
 * Topic: university 2022 Scheme - NAND and NOR Implementation
 */

#include <stdio.h>
#include <stdbool.h>

// Basic gate definitions
bool nand(bool a, bool b) {
 return !(a && b);
}

bool nor(bool a, bool b) {
 return !(a || b);
}

// === NAND as Universal Gate ===

// NOT using NAND: F = (A * A)' = A'
bool not_using_nand(bool a) {
 return nand(a, a);
}

// AND using two NANDs: F = ((A * B)')' = A * B
bool and_using_nand(bool a, bool b) {
 bool temp = nand(a, b); // First NAND: (A*B)'
 return nand(temp, temp); // Second NAND inverts
}

// OR using three NANDs: F = (A' * B')' = A + B
bool or_using_nand(bool a, bool b) {
 bool a_not = nand(a, a); // A' (inverter)
 bool b_not = nand(b, b); // B' (inverter)
 return nand(a_not, b_not); // NAND of inverted inputs
}

// === NOR as Universal Gate ===

// NOT using NOR: F = (A + A)' = A'
bool not_using_nor(bool a) {
 return nor(a, a);
}

// OR using two NORs: F = ((A + B)')' = A + B
bool or_using_nor(bool a, bool b) {
 bool temp = nor(a, b); // First NOR: (A+B)'
 return nor(temp, temp); // Second NOR inverts
}

// AND using three NORs: F = (A' + B')' = A * B
bool and_using_nor(bool a, bool b) {
 bool a_not = nor(a, a); // A' (inverter)
 bool b_not = nor(b, b); // B' (inverter)
 return nor(a_not, b_not); // NOR of inverted inputs
}

// === NAND-NAND Implementation for SOP: F = AB + CD ===
/*
 * Step 1: Original SOP: F = AB + CD
 * Step 2: Double complement: F = ((AB + CD)')'
 * Step 3: Apply De Morgan: F = ((AB)' * (CD)')'
 * This is NAND of NANDs - two-level NAND-NAND circuit
 */
bool nand_nand_f(bool a, bool b, bool c, bool d) {
 // Level 1: NAND gates for each product term
 bool term1 = nand(a, b); // (AB)'
 bool term2 = nand(c, d); // (CD)'

 // Level 2: NAND gate combines terms (OR operation)
 return nand(term1, term2); // ((AB)' * (CD)')'
}

// === NOR-NOR Implementation for POS: F = (A+B)(C+D) ===
/*
 * Step 1: Original POS: F = (A+B)(C+D)
 * Step 2: Double complement: F = (((A+B)(C+D))')'
 * Step 3: Apply De Morgan: F = ((A+B)' + (C+D)')'
 * This is NOR of NORs - two-level NOR-NOR circuit
 */
bool nor_nor_f(bool a, bool b, bool c, bool d) {
 // Level 1: NOR gates for each sum term
 bool term1 = nor(a, b); // (A+B)'
 bool term2 = nor(c, d); // (C+D)'

 // Level 2: NOR gate combines terms (AND operation)
 return nor(term1, term2); // ((A+B)' + (C+D)')
}

// === Handling Single Variable: F = AB + C ===
/*
 * For single literal C, we need an extra inverter
 * NAND-NAND: F = ((AB)' * C')'
 * C requires NAND(C,C) to create C'
 */
bool nand_nand_single_literal(bool a, bool b, bool c) {
 bool ab_nand = nand(a, b); // (AB)'
 bool c_not = nand(c, c); // C' (inverter)
 return nand(ab_nand, c_not); // ((AB)' * C')'
}

// Print boolean as 0/1
#define BOOL_STR(x) ((x) ? "1" : "0")

int main() {
 printf("=============================================================\n");
 printf(" NAND and NOR Universal Gate Implementation\n");
 printf("=============================================================\n\n");

 // Test NAND universal gates
 printf("--- NAND as Universal Gate ---\n");
 printf("NOT(1) = %s, NOT(0) = %s\n", 
 BOOL_STR(not_using_nand(1)), BOOL_STR(not_using_nand(0)));
 printf("AND(1,1) = %s, AND(1,0) = %s\n", 
 BOOL_STR(and_using_nand(1, 1)), BOOL_STR(and_using_nand(1, 0)));
 printf("OR(1,0) = %s, OR(0,0) = %s\n\n", 
 BOOL_STR(or_using_nand(1, 0)), BOOL_STR(or_using_nand(0, 0)));

 // Test NOR universal gates
 printf("--- NOR as Universal Gate ---\n");
 printf("NOT(1) = %s, NOT(0) = %s\n", 
 BOOL_STR(not_using_nor(1)), BOOL_STR(not_using_nor(0)));
 printf("OR(1,0) = %s, OR(0,0) = %s\n", 
 BOOL_STR(or_using_nor(1, 0)), BOOL_STR(or_using_nor(0, 0)));
 printf("AND(1,0) = %s, AND(1,1) = %s\n\n", 
 BOOL_STR(and_using_nor(1, 0)), BOOL_STR(and_using_nor(1, 1)));

 // Verify NAND-NAND: F = AB + CD
 printf("--- NAND-NAND Implementation: F = AB + CD ---\n");
 printf("A B C D | Expected | NAND-NAND\n");
 printf("-------+----------+----------\n");

 int errors = 0;
 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 for (int d = 0; d <= 1; d++) {
 bool expected = (a && b) || (c && d);
 bool result = nand_nand_f(a, b, c, d);
 printf(" %d %d %d %d | %d | %d\n", 
 a, b, c, d, expected, result);
 if (expected != result) errors++;
 }
 }
 }
 }

 // Verify NOR-NOR: F = (A+B)(C+D)
 printf("\n--- NOR-NOR Implementation: F = (A+B)(C+D) ---\n");
 printf("A B C D | Expected | NOR-NOR\n");
 printf("-------+----------+----------\n");

 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 for (int d = 0; d <= 1; d++) {
 bool expected = (a || b) && (c || d);
 bool result = nor_nor_f(a, b, c, d);
 printf(" %d %d %d %d | %d | %d\n", 
 a, b, c, d, expected, result);
 if (expected != result) errors++;
 }
 }
 }
 }

 // Verify single literal handling: F = AB + C
 printf("\n--- Single Literal: F = AB + C ---\n");
 printf("A B C | Expected | NAND-NAND\n");
 printf("-----+----------+----------\n");

 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 bool expected = (a && b) || c;
 bool result = nand_nand_single_literal(a, b, c);
 printf(" %d %d %d | %d | %d\n", 
 a, b, c, expected, result);
 if (expected != result) errors++;
 }
 }
 }

 printf("\n=============================================================\n");
 if (errors == 0) {
 printf(" ALL TESTS PASSED! Universal gates verified.\n");
 } else {
 printf(" ERROR: %d test(s) failed!\n", errors);
 }
 printf("=============================================================\n");

 return 0;
}

/*
 * NAND and NOR Universal Gate Implementation
 * university 2022 Scheme - Digital Logic Design
 * Demonstrates NAND-NAND and NOR-NOR implementations
 */

public class NandNorImplementation {

 // Basic NAND gate
 public static boolean nand(boolean a, boolean b) {
 return !(a && b);
 }

 // Basic NOR gate
 public static boolean nor(boolean a, boolean b) {
 return !(a || b);
 }

 // ========== NAND as Universal Gate ==========

 /**
 * NOT using NAND: Connect both inputs together
 * F = (A · A)' = A' (Idempotent + Complement law)
 */
 public static boolean notNand(boolean a) {
 return nand(a, a);
 }

 /**
 * AND using two NAND gates
 * F = ((A · B)')' = A · B
 */
 public static boolean andNand(boolean a, boolean b) {
 boolean temp = nand(a, b); // Step 1: NAND = (A·B)'
 return nand(temp, temp); // Step 2: Invert = ((A·B)')'
 }

 /**
 * OR using three NAND gates
 * F = (A' · B')' = A + B (De Morgan's theorem)
 * Requires: 2 NANDs as inverters + 1 NAND for final output
 */
 public static boolean orNand(boolean a, boolean b) {
 boolean aNot = nand(a, a); // Inverter for A
 boolean bNot = nand(b, b); // Inverter for B
 return nand(aNot, bNot); // NAND of inverted inputs
 }

 // ========== NOR as Universal Gate ==========

 /**
 * NOT using NOR: Connect both inputs together
 * F = (A + A)' = A'
 */
 public static boolean notNor(boolean a) {
 return nor(a, a);
 }

 /**
 * OR using two NOR gates
 * F = ((A + B)')' = A + B
 */
 public static boolean orNor(boolean a, boolean b) {
 boolean temp = nor(a, b); // First NOR = (A+B)'
 return nor(temp, temp); // Second NOR inverts
 }

 /**
 * AND using three NOR gates
 * F = (A' + B')' = A · B (De Morgan's theorem)
 */
 public static boolean andNor(boolean a, boolean b) {
 boolean aNot = nor(a, a); // Inverter for A
 boolean bNot = nor(b, b); // Inverter for B
 return nor(aNot, bNot); // NOR of inverted inputs
 }

 // ========== NAND-NAND Implementation ==========

 /**
 * NAND-NAND Implementation for SOP: F = AB + CD
 * 
 * Conversion Steps:
 * 1. Original: F = AB + CD
 * 2. Double complement: F = ((AB + CD)')'
 * 3. De Morgan: F = ((AB)' · (CD)')'
 * 
 * Circuit: Two Level NAND
 * - Level 1: NAND gates for each product term
 * - Level 2: NAND gate for sum (OR equivalent)
 */
 public static boolean nandNandImplementation(boolean a, boolean b, 
 boolean c, boolean d) {
 // Level 1: First NAND gate - AB product term
 boolean abTerm = nand(a, b); // Output: (AB)'

 // Level 1: Second NAND gate - CD product term 
 boolean cdTerm = nand(c, d); // Output: (CD)'

 // Level 2: Final NAND gate - combines terms (OR operation)
 return nand(abTerm, cdTerm); // Output: ((AB)' · (CD)')'
 }

 /**
 * NOR-NOR Implementation for POS: F = (A+B)(C+D)
 * 
 * Conversion Steps:
 * 1. Original: F = (A+B)(C+D)
 * 2. Double complement: F = (((A+B)(C+D))')'
 * 3. De Morgan: F = ((A+B)' + (C+D)')'
 * 
 * Circuit: Two Level NOR
 * - Level 1: NOR gates for each sum term
 * - Level 2: NOR gate for product (AND equivalent)
 */
 public static boolean norNorImplementation(boolean a, boolean b,
 boolean c, boolean d) {
 // Level 1: First NOR gate - (A+B) sum term
 boolean abTerm = nor(a, b); // Output: (A+B)'

 // Level 1: Second NOR gate - (C+D) sum term
 boolean cdTerm = nor(c, d); // Output: (C+D)'

 // Level 2: Final NOR gate - combines terms (AND operation)
 return nor(abTerm, cdTerm); // Output: ((A+B)' + (C+D)')
 }

 /**
 * Handling Single Literal Term: F = AB + C
 * 
 * For single variable C in SOP, we need extra inverter
 * because the second-level NAND expects complemented inputs.
 * 
 * NAND-NAND: F = ((AB)' · C')'
 */
 public static boolean nandNandWithLiteral(boolean a, boolean b, boolean c) {
 boolean abTerm = nand(a, b); // (AB)'
 boolean cNot = nand(c, c); // C' - extra inverter needed
 return nand(abTerm, cNot); // ((AB)' · C')'
 }

 // Helper to convert boolean to int
 private static int b2i(boolean b) {
 return b ? 1 : 0;
 }

 public static void main(String[] args) {
 System.out.println("============================================================");
 System.out.println(" NAND and NOR Universal Gate Implementation");
 System.out.println("============================================================\n");

 // Test 1: NAND as Universal Gate
 System.out.println("--- NAND as Universal Gate ---");
 System.out.println("NOT using NAND: NOT(1)=" + b2i(notNand(true)) + 
 ", NOT(0)=" + b2i(notNand(false)));
 System.out.println("AND using NAND: 1·1=" + b2i(andNand(true, true)) + 
 ", 1·0=" + b2i(andNand(true, false)));
 System.out.println("OR using NAND: 1+0=" + b2i(orNand(true, false)) + 
 ", 0+0=" + b2i(orNand(false, false)));

 // Test 2: NOR as Universal Gate
 System.out.println("\n--- NOR as Universal Gate ---");
 System.out.println("NOT using NOR: NOT(1)=" + b2i(notNor(true)) + 
 ", NOT(0)=" + b2i(notNor(false)));
 System.out.println("OR using NOR: 1+1=" + b2i(orNor(true, true)) + 
 ", 1+0=" + b2i(orNor(true, false)));
 System.out.println("AND using NOR: 1·0=" + b2i(andNor(true, false)) + 
 ", 1·1=" + b2i(andNor(true, true)));

 // Test 3: NAND-NAND Implementation - F = AB + CD
 System.out.println("\n--- NAND-NAND: F = AB + CD ---");
 System.out.println("A B C D | Expected | NAND-NAND | Status");
 System.out.println("--------|----------|-----------|--------");

 int errorCount = 0;
 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 for (int d = 0; d <= 1; d++) {
 boolean inA = (a == 1), inB = (b == 1);
 boolean inC = (c == 1), inD = (d == 1);

 boolean expected = (inA && inB) || (inC && inD);
 boolean result = nandNandImplementation(inA, inB, inC, inD);

 String status = (expected == result) ? "OK" : "FAIL";
 if (expected != result) errorCount++;

 System.out.println(" " + a + " " + b + " " + c + " " + d + 
 " | " + b2i(expected) + " | " + 
 b2i(result) + " | " + status);
 }
 }
 }
 }

 // Test 4: NOR-NOR Implementation - F = (A+B)(C+D)
 System.out.println("\n--- NOR-NOR: F = (A+B)(C+D) ---");
 System.out.println("A B C D | Expected | NOR-NOR | Status");
 System.out.println("--------|----------|-----------|--------");

 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 for (int d = 0; d <= 1; d++) {
 boolean inA = (a == 1), inB = (b == 1);
 boolean inC = (c == 1), inD = (d == 1);

 boolean expected = (inA || inB) && (inC || inD);
 boolean result = norNorImplementation(inA, inB, inC, inD);

 String status = (expected == result) ? "OK" : "FAIL";
 if (expected != result) errorCount++;

 System.out.println(" " + a + " " + b + " " + c + " " + d + 
 " | " + b2i(expected) + " | " + 
 b2i(result) + " | " + status);
 }
 }
 }
 }

 // Test 5: Single Literal Handling - F = AB + C
 System.out.println("\n--- Single Literal: F = AB + C ---");
 System.out.println("A B C | Expected | NAND-NAND | Status");
 System.out.println("------|----------|-----------|--------");

 for (int a = 0; a <= 1; a++) {
 for (int b = 0; b <= 1; b++) {
 for (int c = 0; c <= 1; c++) {
 boolean inA = (a == 1), inB = (b == 1), inC = (c == 1);

 boolean expected = (inA && inB) || inC;
 boolean result = nandNandWithLiteral(inA, inB, inC);

 String status = (expected == result) ? "OK" : "FAIL";
 if (expected != result) errorCount++;

 System.out.println(" " + a + " " + b + " " + c + 
 " | " + b2i(expected) + " | " + 
 b2i(result) + " | " + status);
 }
 }
 }

 System.out.println("\n============================================================");
 if (errorCount == 0) {
 System.out.println(" ALL TESTS PASSED!");
 } else {
 System.out.println(" ERRORS: " + errorCount + " test(s) failed!");
 }
 System.out.println("============================================================");
 }
}
